INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '83383091-cb2e-4c4e-bbbf-9f4c2c27808f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jetpack Compose — Efficiently Handling Network Errors with Retrofit$escape$,
  $escape$When using Retrofit with OkHttp in Jetpack Compose, you can handle network errors by creating a custom ExceptionHandler. This can be done by creating a class that implements the Retrofit2.CallAdapter.Factory interface. Then, in your Compose app, you can use the CoroutineScope to handle the network call and its potential errors. To demonstrate this, consider the following code snippet.$escape$,
  $escape$
   data class User(val id: Int, val name: String)

   @Serializable

   data class ErrorMessage(val code: Int, val message: String)

   private val retrofit = Retrofit.Builder()

       .baseUrl("https://api.example.com/")

       .client(OkHttpClient.Builder().build())

       .addConverterFactory(GsonConverterFactory.create())

       .build()

   private fun getUser(): Flow<User> {

       return Retrofit2.create(User::class.java, retrofit)

           .asFlow()

           .catch { e: Throwable ->
               if (e is IOException) {
                   emit(ErrorMessage(-1, "Network error"))
               } else {
                   throw e
               }
           }

   }
$escape$,
  $escape$kotlin$escape$,
