INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '21fe17a2-3c38-4ac9-bd5e-72ef72106f20',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jetpack Compose: Mastering Gradle Build Variants for Android Apps$escape$,
  $escape$When building Android apps with Jetpack Compose, managing multiple build variants is crucial. Product flavors and build types enable you to create different versions of your app with distinct features or configurations. In your `build.gradle` file, define product flavors using the `flavorDimensions` and `productFlavors` properties. For example:

```groovy
defaultConfig {    // Common configurations for all build types}

productFlavors {
    flavor1 {
        // Flavor-specific configurations
    }
    flavor2 {
        // Flavor-specific configurations
    }
}

buildTypes {
    release {
        // Release-specific configurations
    }
    debug {
        // Debug-specific configurations
    }
}
```$escape$,
  $escape$null$escape$,
